import json,re
from pathlib import Path
base=Path('/home/vscode/.cursor/projects/workspaces-agno/agent-transcripts')
for p in sorted(base.glob('*/*.jsonl'), key=lambda x:x.stat().st_mtime, reverse=True):
    text=p.read_text(errors='ignore')
    if not re.search(r'bootstrap', text, re.I):
        continue
    uuid=p.stem
    user_has=False
    firstq=''
    for line in text.splitlines():
        try: obj=json.loads(line)
        except: continue
        if obj.get('role')=='user':
            s=''
            for c in obj.get('message',{}).get('content',[]):
                if c.get('type')=='text': s += c.get('text','')+'\n'
            if not firstq:
                m=re.search(r'<user_query>\s*(.*?)\s*</user_query>', s, re.S)
                firstq=' '.join((m.group(1) if m else s).split())[:100]
            if re.search(r'bootstrap', s, re.I):
                user_has=True
                break
    print(f"{uuid}\tuser_query_has_bootstrap={user_has}\t{firstq}")
